I think we need to create the final passwd file before accessing it.  Something like:

```diff
diff --git a/libpod/container_internal_common.go b/libpod/container_internal_common.go
index d9b7e33da0..b686c6bbf8 100644
--- a/libpod/container_internal_common.go
+++ b/libpod/container_internal_common.go
@@ -195,15 +195,16 @@ func (c *Container) generateSpec(ctx context.Context) (s *spec.Spec, cleanupFunc
 			cleanupFunc()
 		}
 	}()
+
+
+	if err := c.makeBindMounts(); err != nil {
+		return nil, nil, err
+	}
+
 	overrides := c.getUserOverrides()
 	execUser, err := lookup.GetUserGroupInfo(c.state.Mountpoint, c.config.User, overrides)
 	if err != nil {
-		if slices.Contains(c.config.HostUsers, c.config.User) {
-			execUser, err = lookupHostUser(c.config.User)
-		}
-		if err != nil {
-			return nil, nil, err
-		}
+		return nil, nil, err
 	}

 	// NewFromSpec() is deprecated according to its comment
@@ -236,10 +237,6 @@ func (c *Container) generateSpec(ctx context.Context) (s *spec.Spec, cleanupFunc
 		g.SetProcessApparmorProfile(updatedProfile)
 	}

-	if err := c.makeBindMounts(); err != nil {
-		return nil, nil, err
-	}
-
 	if err := c.mountNotifySocket(g); err != nil {
 		return nil, nil, err
 	}
```
